const filters = $input.item.json.body.filters || {};
const idEmpresa = $input.item.json.body.idEmpresa;
const conditions = [];
const params = [idEmpresa];
const page = $input.item.json.body.page || 1;
const limit = $input.item.json.body.limit || 10;
const offset = (page - 1) * limit;
let paramIndex = 2;

let query = `SELECT d.id, d.direccion, d.codigo_postal, d.id_localidad, d.id_empresa, d.activo, d.created_at, l.localidad, l.id_provincia, p.provincia, p.id_pais, pa.pais, COUNT(*) OVER() AS total_count, COUNT(*) FILTER (WHERE d.activo = true)  OVER() AS total_activos, COUNT(*) FILTER (WHERE d.activo = false)  OVER() AS total_inactivos
FROM direccion_empresa d 
LEFT JOIN localidad l ON l.id = d.id_localidad
LEFT JOIN provincia p ON p.id = l.id_provincia
LEFT JOIN pais pa ON pa.id = p.id_pais 
WHERE d.id_empresa = $1`;

if (filters.searchText && filters.searchText.trim() !== '') {
  conditions.push(`(d.direccion ILIKE $${paramIndex})`);
  params.push(`%${filters.searchText}%`);
  paramIndex++;
}

if (filters.pais && filters.pais.trim() !== '') {
  conditions.push(`pa.pais = $${paramIndex}`);
  params.push(filters.pais);
  paramIndex++;
}

if (filters.status && filters.status.trim() !== '') {
  if (filters.status === 'activa') {
    conditions.push(`d.activo = true`);
  } else if (filters.status === 'baja') {
    conditions.push(`d.activo = false`);
  }
}

if (conditions.length > 0) {
  query += ' AND ' + conditions.join(' AND ');
}

query += ' GROUP BY d.id, d.direccion, d.codigo_postal, d.id_localidad, d.id_empresa, d.activo, d.created_at, l.localidad, l.id_provincia, p.provincia, p.id_pais, pa.pais';
query += ' ORDER BY d.created_at ASC';
query += ` LIMIT ${limit} OFFSET ${offset}`;

return [{
  json: {
    query: query,
    params: params.join(',')
  }
}];

const body = $input.item.json.body;

const fields = ['direccion', 'codigo_postal', 'id_empresa', 'id_localidad', 'activo'];
const values = [body.direccionData.direccion, body.direccionData.codigoPostal, body.direccionData.id_empresa, body.direccionData.id_localidad, body.direccionData.activo];

const placeholders = values.map((_, i) => `$${i + 1}`).join(', ');

return [{
  json: {
    query: `INSERT INTO direccion_empresa (${fields.join(', ')})
            VALUES (${placeholders})
            RETURNING id, direccion, codigo_postal, id_empresa, id_localidad, activo, created_at`,
    params: values.join(',')
  }
}];

const jwt = require('jsonwebtoken');

const JWT_SECRET = 'passEncriptada';
const PUBLIC_ACTIONS = ['getRole'];

const body = $json.body;
const action = body?.action || '';

if (PUBLIC_ACTIONS.includes(action)) {
  return [{ json: { ...$json, _bypass: true } }];
}

const headers = $json.headers || {};
const authHeader = headers['authorization'] || headers['Authorization'] || '';
const bodyToken  = body?.token || '';
const rawToken   = authHeader || bodyToken;

const token = rawToken.replace('Bearer ', '').trim();

if (!token) {
  return [{ json: { _authError: true, status: 401, message: 'Token no proporcionado' } }];
}

try {
  const decoded = jwt.verify(token, JWT_SECRET);
  return [{
    json: {
      ...$json,
      _auth: { id: decoded.id, email: decoded.email, role: decoded.role }
    }
  }];
} catch (err) {
  return [{ json: { _authError: true, status: 401, message: 'Token invÃ¡lido o expirado - ' + err.message } }];
}
